#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e6;int n,buf[N],*tmp=buf,*G[N],d[N],m,a[N],P[N],ans;
inline void dfs(int u)
{
	for(int i=0;i<d[u];++i)dfs(G[u][i]);
	for(int i=0;i<d[u];++i)P[i]=a[G[u][i]]-1;
	std::sort(P,P+d[u]);int p=0;
	while(p<d[u]&&P[p]+a[u]<=m)a[u]+=P[p++],++ans;
}
int main()
{
	n=read();m=read();for(int i=0;i<n;++i)a[i]=read();
	for(int i=0;i<n;++i)
	{
		d[i]=read();G[i]=tmp;tmp+=d[i];a[i]+=d[i];
		for(int j=0;j<d[i];++j)G[i][j]=read();
	}
	dfs(0);printf("%d\n",ans);return 0;
}
